import { useEffect } from 'react';
export function useKeyboardReorder<T extends { id: string }>(items: ReadonlyArray<T>, focusedId: string | null, onReorder: (next: ReadonlyArray<T>) => void) {
  useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      if (!e.altKey || !focusedId) return;
      const idx = items.findIndex(i => i.id === focusedId);
      if (idx < 0) return;
      if (e.key === 'ArrowDown' && idx < items.length - 1) { e.preventDefault(); const next = items.slice(); [next[idx], next[idx + 1]] = [next[idx + 1], next[idx]]; onReorder(next); }
      else if (e.key === 'ArrowUp' && idx > 0) { e.preventDefault(); const next = items.slice(); [next[idx], next[idx - 1]] = [next[idx - 1], next[idx]]; onReorder(next); }
    };
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, [items, focusedId, onReorder]);
}

