export function CascadingSelect({ parentOptions, parentValue, onParentChange, getChildOptions, childValue, onChildChange }: { parentOptions: ReadonlyArray<{ value: string; label: string }>; parentValue: string; onParentChange: (v: string) => void; getChildOptions: (parent: string) => Promise<ReadonlyArray<{ value: string; label: string }>>; childValue: string; onChildChange: (v: string) => void }) {
  const [childOptions, setChildOptions] = useState<ReadonlyArray<{ value: string; label: string }>>([]);
  const [loadingChild, setLoadingChild] = useState(false);
  useEffect(() => {
    setLoadingChild(true);
