    });
  }, [parentValue, getChildOptions]);
  return (
    <div className="flex gap-2">
      <select value={parentValue} onChange={(e) => onParentChange(e.target.value)} className="h-9 px-3 text-[14px] border border-[oklch(0.85_0.005_250)] rounded"><option value="">Choose\u2026</option>{parentOptions.map(o => <option key={o.value} value={o.value}>{o.label}</option>)}</select>
