import { useRef, useMemo } from 'react';
import { BufferGeometry, Float32BufferAttribute, Points, PointsMaterial, Vector3 } from 'three';
function ParticlesObject() {
  const ref = useRef<Points>(null);
  const geo = useMemo(() => {
    const g = new BufferGeometry();
    const positions = new Float32Array(300 * 3);
    for (let i = 0; i < 300; i++) { positions[i * 3] = (Math.random() - 0.5) * 10; positions[i * 3 + 1] = (Math.random() - 0.5) * 6; positions[i * 3 + 2] = (Math.random() - 0.5) * 2; }
    g.setAttribute('position', new Float32BufferAttribute(positions, 3));
    return g;
  }, []);
  const mouse = useRef(new Vector3());
  useFrame(({ pointer }) => {
    mouse.current.set(pointer.x * 5, pointer.y * 3, 0);
    if (ref.current) {
      const positions = (ref.current.geometry.attributes.position.array as Float32Array);
      for (let i = 0; i < positions.length; i += 3) {
        const dx = positions[i] - mouse.current.x; const dy = positions[i + 1] - mouse.current.y;
        const distSq = dx * dx + dy * dy;
        if (distSq < 4) { positions[i] += dx * 0.02; positions[i + 1] += dy * 0.02; }
      }
      ref.current.geometry.attributes.position.needsUpdate = true;
    }
  });
  return <points ref={ref} geometry={geo}><pointsMaterial color="oklch(0.55 0.18 250)" size={0.05} transparent opacity={0.6} /></points>;
}
export function ParticleField() {
  return <div className="absolute inset-0 -z-10"><Canvas camera={{ position: [0, 0, 5] }}><ParticlesObject /></Canvas></div>;
}

