import { useEffect, useRef } from 'react';
export function HeadingValidator({ children }: { children: React.ReactNode }) {
  const ref = useRef<HTMLDivElement | null>(null);
  useEffect(() => {
    if (process.env.NODE_ENV !== 'development') return;
    const headings = Array.from(ref.current?.querySelectorAll('h1, h2, h3, h4, h5, h6') ?? []) as HTMLHeadingElement[];
    let lastLevel = 0;
    for (const h of headings) {
      const level = parseInt(h.tagName.slice(1), 10);
      if (lastLevel > 0 && level > lastLevel + 1) console.warn(`Heading hierarchy skipped: ${h.tagName} after h${lastLevel}`, h);
      lastLevel = level;
    }
  });
  if (process.env.NODE_ENV !== 'development') return <>{children}</>;
  return <div ref={ref}>{children}</div>;
}

import { useEffect, useRef } from 'react';
const prefetched = new Set<string>();
export function useHoverPrefetch(ref: React.RefObject<HTMLAnchorElement | null>, href: string) {
  const timerRef = useRef<number | null>(null);
  useEffect(() => {
    const el = ref.current; if (!el) return;
    const onEnter = () => { timerRef.current = window.setTimeout(() => {
      if (prefetched.has(href)) return;
      const link = document.createElement('link');
      link.rel = 'prefetch'; link.href = href; document.head.appendChild(link);
      prefetched.add(href);
    }, 200); };
    const onLeave = () => { if (timerRef.current) window.clearTimeout(timerRef.current); };
    el.addEventListener('mouseenter', onEnter);
    el.addEventListener('mouseleave', onLeave);
    return () => { el.removeEventListener('mouseenter', onEnter); el.removeEventListener('mouseleave', onLeave); };
  }, [ref, href]);
}

