import { useState, useEffect, useRef } from 'react';
export function useAutoSaveForm<T>(value: T, save: (v: T) => Promise<void>, debounceMs = 1500) {
  const [state, setState] = useState<'idle' | 'editing' | 'saving' | 'saved'>('idle');
  const [savedAt, setSavedAt] = useState(Date.now());
  const lastSaved = useRef(value);
  const timerRef = useRef<number | null>(null);
  useEffect(() => {
    if (value === lastSaved.current) return;
    setState('editing');
    if (timerRef.current) window.clearTimeout(timerRef.current);
    timerRef.current = window.setTimeout(async () => {
      setState('saving');
      try { await save(value); lastSaved.current = value; setSavedAt(Date.now()); setState('saved'); } catch { setState('idle'); }
    }, debounceMs);
  }, [value, save, debounceMs]);
  return { state, savedAt };
}
export function SaveStatus({ state, savedAt }: { state: 'idle' | 'editing' | 'saving' | 'saved'; savedAt: number }) {
  const ago = Math.floor((Date.now() - savedAt) / 1000);
  const text = state === 'editing' ? 'Editing\u2026' : state === 'saving' ? 'Saving\u2026' : state === 'saved' ? `Saved \u00B7 ${ago}s ago` : 'Ready';
  return <span className="text-[11px] text-[oklch(0.55_0.005_250)]" role="status" aria-live="polite">{text}</span>;
}

