      <div className="absolute inset-0" style={{ transformStyle: 'preserve-3d', transform: `rotateX(${tilt.x}deg) rotateY(${tilt.y}deg)`, transition: tilt.x === 0 && tilt.y === 0 ? 'transform 400ms cubic-bezier(0.22, 1, 0.36, 1)' : 'none' }}>
        <div className="absolute inset-0 bg-white rounded-lg shadow-lg" style={{ backfaceVisibility: 'hidden' }}>{front}</div>
