import { useEffect } from 'react';
export function useSequentialErrorAnnounce(errors: ReadonlyArray<{ fieldId: string; message: string }>, announce: (msg: string) => void) {
  useEffect(() => {
    if (errors.length === 0) return;
    announce(`${errors.length} error${errors.length === 1 ? '' : 's'} found. ${errors[0].message}`);
    const el = document.getElementById(errors[0].fieldId);
    el?.focus();
  }, [errors, announce]);
}

import { useState, useTransition, useMemo } from 'react';
export function FilterableList({ items }: { items: ReadonlyArray<{ id: string; title: string }> }) {
  const [query, setQuery] = useState('');
  const [deferredQuery, setDeferredQuery] = useState('');
  const [isPending, startTransition] = useTransition();
  const onChange = (v: string) => {
    setQuery(v);
    startTransition(() => setDeferredQuery(v));
  };
  const filtered = useMemo(() => items.filter(i => i.title.toLowerCase().includes(deferredQuery.toLowerCase())), [items, deferredQuery]);
  return (
    <div>
      <input value={query} onChange={(e) => onChange(e.target.value)} className="w-full h-9 px-3 border rounded" />
      <ul style={{ opacity: isPending ? 0.5 : 1, transition: 'opacity 100ms' }}>{filtered.map(i => <li key={i.id}>{i.title}</li>)}</ul>
    </div>
  );
}

