import { useState, useMemo } from 'react';
export interface DataColumn<R> { id: string; label: string; accessor: (r: R) => string | number; sortable?: boolean; filterable?: boolean; }
export function DataTable<R extends { id: string }>({ columns, rows, pageSize = 20 }: { columns: ReadonlyArray<DataColumn<R>>; rows: ReadonlyArray<R>; pageSize?: number }) {
  const [sortKey, setSortKey] = useState<string | null>(null);
  const [sortDir, setSortDir] = useState<'asc' | 'desc'>('asc');
  const [filters, setFilters] = useState<Record<string, string>>({});
  const [page, setPage] = useState(0);
  const processed = useMemo(() => {
    let r = rows.slice();
    for (const [cid, q] of Object.entries(filters)) { if (!q) continue; const col = columns.find(c => c.id === cid); if (col) r = r.filter(row => String(col.accessor(row)).toLowerCase().includes(q.toLowerCase())); }
    if (sortKey) { const col = columns.find(c => c.id === sortKey)!; r.sort((a, b) => { const av = String(col.accessor(a)); const bv = String(col.accessor(b)); return sortDir === 'asc' ? av.localeCompare(bv) : bv.localeCompare(av); }); }
    return r;
  }, [rows, filters, columns, sortKey, sortDir]);
  const paginated = processed.slice(page * pageSize, (page + 1) * pageSize);
  const totalPages = Math.ceil(processed.length / pageSize);
  return (
    <div>
      <table className="w-full text-[13px]">
        <thead>
          <tr>{columns.map(c => <th key={c.id} className="text-left text-[11px] uppercase tracking-wider font-semibold px-3 py-2 text-[oklch(0.55_0.005_250)] border-b border-[oklch(0.92_0.005_250)]"><button type="button" disabled={!c.sortable} onClick={() => { if (sortKey === c.id) setSortDir(d => d === 'asc' ? 'desc' : 'asc'); else { setSortKey(c.id); setSortDir('asc'); } }}>{c.label}{sortKey === c.id && (sortDir === 'asc' ? ' \u2191' : ' \u2193')}</button></th>)}</tr>
          <tr>{columns.map(c => <th key={c.id} className="px-3 pb-2 border-b border-[oklch(0.92_0.005_250)]">{c.filterable ? <input value={filters[c.id] ?? ''} onChange={(e) => setFilters(f => ({ ...f, [c.id]: e.target.value }))} className="w-full h-7 px-2 text-[11px] border border-[oklch(0.85_0.005_250)] rounded" placeholder="Filter\u2026" /> : null}</th>)}</tr>
        </thead>
        <tbody>{paginated.map(row => <tr key={row.id} className="border-b border-[oklch(0.95_0.005_250)]">{columns.map(c => <td key={c.id} className="px-3 py-2">{String(c.accessor(row))}</td>)}</tr>)}</tbody>
      </table>
      <div className="flex justify-between items-center mt-3 text-[12px]">
        <span className="text-[oklch(0.55_0.005_250)]">{processed.length} rows</span>
        <div className="flex gap-2"><button type="button" onClick={() => setPage(p => Math.max(0, p - 1))} disabled={page === 0}>\u2039</button><span>{page + 1} / {totalPages}</span><button type="button" onClick={() => setPage(p => Math.min(totalPages - 1, p + 1))} disabled={page >= totalPages - 1}>\u203A</button></div>
      </div>
    </div>
  );
}

import { useEffect, useState } from 'react';
export function useDualPalettes() {
  const [actionOpen, setActionOpen] = useState(false);
  const [searchOpen, setSearchOpen] = useState(false);
  useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      if (!(e.metaKey || e.ctrlKey)) return;
      if (e.shiftKey && e.key === 'P') { e.preventDefault(); setActionOpen(true); }
      else if (e.key === 'p' && !e.shiftKey) { e.preventDefault(); setSearchOpen(true); }
    };
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, []);
  return { actionOpen, setActionOpen, searchOpen, setSearchOpen };
}

