export interface SlopeItem { label: string; before: number; after: number; }
export function SlopeChart({ items, width = 480, height = 320 }: { items: ReadonlyArray<SlopeItem>; width?: number; height?: number }) {
  const allValues = items.flatMap(i => [i.before, i.after]);
  const min = Math.min(...allValues), max = Math.max(...allValues);
  const yScale = (v: number) => 30 + ((max - v) / (max - min)) * (height - 60);
  const xLeft = 100, xRight = width - 100;
  return (
    <svg width={width} height={height} className="font-sans">
      <text x={xLeft} y={20} fontSize="11" textAnchor="middle" fill="oklch(0.55 0.005 250)">Before</text>
      <text x={xRight} y={20} fontSize="11" textAnchor="middle" fill="oklch(0.55 0.005 250)">After</text>
      {items.map(i => { const direction = i.after > i.before ? 'up' : i.after < i.before ? 'down' : 'flat'; const color = direction === 'up' ? 'oklch(0.55 0.14 145)' : direction === 'down' ? 'oklch(0.6 0.18 25)' : 'oklch(0.55 0.005 250)'; return (
        <g key={i.label}>
          <line x1={xLeft} y1={yScale(i.before)} x2={xRight} y2={yScale(i.after)} stroke={color} strokeWidth="1.5" />
          <circle cx={xLeft} cy={yScale(i.before)} r={3} fill={color} />
          <circle cx={xRight} cy={yScale(i.after)} r={3} fill={color} />
          <text x={xLeft - 8} y={yScale(i.before) + 4} fontSize="11" textAnchor="end" fill="oklch(0.45 0.005 250)">{i.label}</text>
          <text x={xRight + 8} y={yScale(i.after) + 4} fontSize="11" textAnchor="start" fill="oklch(0.45 0.005 250)">{i.after}</text>
        </g>
      ); })}
    </svg>
  );
}

